import { Dropdown, DropdownItem, DropdownList, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
import * as React from 'react';
import { useTranslation } from 'react-i18next';
import { Match } from '../../model/flow-query';
import { BackAndForthIcon } from '../icons';

export interface MatchDropdownProps {
  selected: Match;
  setMatch: (l: Match) => void;
  allowBidirectional?: boolean;
  id?: string;
}

export const MatchValues = ['any', 'all', 'bidirectional'] as Match[];

export const MatchDropdown: React.FC<MatchDropdownProps> = ({ allowBidirectional, selected, setMatch, id }) => {
  const { t } = useTranslation('plugin__netobserv-plugin');
  const [isOpen, setOpen] = React.useState(false);

  const getMatchDisplay = (layoutName: Match, toggle?: boolean) => {
    switch (layoutName) {
      case 'any':
        return t('OR');
      case 'all':
        return t('AND');
      case 'bidirectional':
        if (allowBidirectional) {
          if (toggle) {
            return <BackAndForthIcon size="1.5em" />;
          } else {
            return t('Bidirectional');
          }
        } else {
          // display as AND if bidirectional is not allowed here
          return t('AND');
        }
      default:
        return t('Invalid');
    }
  };

  const getToggleIcon = (layoutName: Match) => {
    if (layoutName === 'bidirectional' && allowBidirectional) {
      return <BackAndForthIcon size="1.5em" />;
    }
    return undefined;
  };

  const getToggleText = (layoutName: Match) => {
    switch (layoutName) {
      case 'any':
        return t('OR');
      case 'all':
        return t('AND');
      case 'bidirectional':
        if (allowBidirectional) {
          return undefined;
        } else {
          return t('AND');
        }
      default:
        return t('Invalid');
    }
  };

  return (
    <Dropdown
      data-test={id}
      id={id}
      isOpen={isOpen}
      onOpenChange={setOpen}
      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
        <MenuToggle
          ref={toggleRef}
          data-test={`${id}-dropdown`}
          id={`${id}-dropdown`}
          className="match-dropdown"
          isExpanded={isOpen}
          onClick={() => setOpen(!isOpen)}
          icon={getToggleIcon(selected)}
        >
          {getToggleText(selected)}
        </MenuToggle>
      )}
    >
      <DropdownList>
        {MatchValues.filter(v => allowBidirectional || v !== 'bidirectional').map(v => (
          <DropdownItem
            data-test={v}
            id={v}
            key={v}
            onClick={() => {
              setOpen(false);
              setMatch(v);
            }}
          >
            {getMatchDisplay(v)}
          </DropdownItem>
        ))}
      </DropdownList>
    </Dropdown>
  );
};

export default MatchDropdown;
